export function tooltip(node, text) {
  let tip = createTooltip(node, text)
  return {
    update(newText) {
      tip.setText(newText)
    },
    destroy() {
      tip.remove()
    }
  }
}

Code Bad:
export function tooltip(node, text) {
  createTooltip(node, text)
  // No cleanup - memory leak
  // No update - stale content
}

